-- Kun de TRE nye VM-rundene (16-delsfinale + Norge-Brasil historie + pre-game).
-- Trygt a kjore i Supabase SQL Editor: ROrer IKKE de andre rundene (unnga re-las-fellen).
-- Alle tre seedes med status='open' => live med en gang.

insert into public.event_quizzes (event_id, slug, num, phase, title, sub, hero_img, difficulty, questions, status, sort, published)
values (
  'vm-2026', 'sluttspill-16del', '16', '16-delsfinale',
  '16-delsfinalen — de første utslagskampene', 'Haaland sender Norge videre, Tyskland ut på straffer, Belgias vanvittige snuoperasjon — 28. juni–2. juli.', 'vm-gruppespill-1', 'middels',
  '[{"category": "Resultat", "q": "Hva ble resultatet da Norge møtte Elfenbenskysten i 16-delsfinalen 30. juni?", "options": ["2–2", "3–2 til Norge", "1–0 til Norge", "2–1 til Norge"], "correct": 3, "explanation": "Norge vant 2–1 i Dallas og tok seg videre til åttedelsfinalen — lagets første seier i en VM-utslagsrunde noensinne."}, {"category": "Målscorer", "q": "Hvem scoret Norges avgjørende 2–1-mål mot Elfenbenskysten, sent i andre omgang?", "options": ["Jørgen Strand Larsen", "Alexander Sørloth", "Erling Haaland", "Oscar Bobb"], "correct": 2, "explanation": "Haaland stakk inn vinnermålet i det 86. minutt på et innlegg fra Sander Berge — hans femte mål i VM 2026."}, {"category": "Stjerner", "q": "Hvem sendte Norge i ledelsen med et praktmål i første omgang mot Elfenbenskysten?", "options": ["Antonio Nusa", "Erling Haaland", "Alexander Sørloth", "Martin Ødegaard"], "correct": 0, "explanation": "Nusa curlet inn 1–0 i det 39. minutt; Amad Diallo utlignet for Elfenbenskysten før Haaland avgjorde til slutt."}, {"category": "Drama", "q": "Firedobbelt verdensmester Tyskland ble slått ut på straffespark i 16-delsfinalen. Hvilket lag sto for skrellen?", "options": ["Ecuador", "Sør-Korea", "Sveits", "Paraguay"], "correct": 3, "explanation": "Paraguay vant straffekonkurransen 4–3 etter 1–1 i Boston; Tyskland hadde aldri før tapt en straffekonkurranse i et VM."}, {"category": "Drama", "q": "Belgia lå under 0–2 mot Senegal, men snudde til 3–2 etter ekstraomganger. Hvem avgjorde fra straffemerket i det 117. minutt?", "options": ["Leandro Trossard", "Romelu Lukaku", "Youri Tielemans", "Kevin De Bruyne"], "correct": 2, "explanation": "Tielemans satte den omdiskuterte straffen i det 117. minutt etter langt VAR-opphold; Lukaku og Tielemans hadde tvunget fram ekstraomganger sent i ordinær tid."}, {"category": "Rekord", "q": "Mexico slo Ecuador 2–0 på Estadio Azteca og brøt en lang tørke. Hva slags rekord?", "options": ["Første knockout-seier i VM på 40 år", "Første gang i en VM-finale", "Første VM-seier på hjemmebane noensinne", "Første seier i VM 2026"], "correct": 0, "explanation": "Quiñones og Jiménez scoret; det var Mexicos første seier i en VM-utslagsrunde siden 1986."}, {"category": "Kuriosa", "q": "Marokko slo Nederland ut av VM i 16-delsfinalen. Hvordan ble kampen avgjort?", "options": ["2–1 til Marokko på overtid", "Nederland ble diskvalifisert", "3–0 til Marokko", "På straffespark etter 1–1"], "correct": 3, "explanation": "Marokko vant straffekonkurransen 3–2 i Monterrey etter 1–1; keeper Yassine Bounou ble helten med en avgjørende redning."}, {"category": "Stjerner", "q": "Kylian Mbappé herjet da Frankrike vant 3–0 i sin 16-delsfinale. Hva presterte han?", "options": ["Han ble utvist", "Hat trick", "To mål — og tangerte Messi på topp av VM-toppscorerlista", "Ett mål og to målgivende"], "correct": 2, "explanation": "Mbappés dobbel (pluss et mål av Bradley Barcola) tok ham opp i seks mål — likt med Lionel Messi på toppscorerlista i VM 2026."}, {"category": "Kuriosa", "q": "Turneringens aller første utslagskamp endte 1–0 til Canada over Sør-Afrika, på et sent mål. Hva var historisk for Canada?", "options": ["Canadas første VM-tittel", "Deres første knockout-seier i et VM noensinne", "Deres første VM-seier noensinne", "Canadas første VM-finale"], "correct": 1, "explanation": "Stephen Eustáquio avgjorde på overtid i turneringens første 16-delsfinale (28. juni) — Canadas første seier i en VM-utslagsrunde."}, {"category": "Resultat", "q": "Brasil slet, men vant 2–1 over Japan. Hvem avgjorde med et mål på overtid?", "options": ["Vinícius Júnior", "Casemiro", "Gabriel Martinelli", "Rodrygo"], "correct": 2, "explanation": "Innbytter Martinelli curlet inn vinnermålet på overtid (90+6.); Casemiro hadde utlignet Kaishu Sanos ledermål med en heading."}]'::jsonb, 'open', 16, true
)
on conflict (event_id, slug) do update set
  num=excluded.num, phase=excluded.phase, title=excluded.title, sub=excluded.sub,
  hero_img=excluded.hero_img, difficulty=excluded.difficulty, questions=excluded.questions,
  status=excluded.status, sort=excluded.sort, published=excluded.published;

insert into public.event_quizzes (event_id, slug, num, phase, title, sub, hero_img, difficulty, questions, status, sort, published)
values (
  'vm-2026', 'norge-brasil-historie', '17', 'Historie',
  'Norge–Brasil gjennom historien', 'Brasils uløste gåte: fire møter, null norske tap. Fra 1988 til VM-sjokket i 1998.', 'vm-gruppespill-1', 'middels',
  '[{"category": "Kuriosa", "q": "Norge har en helt spesiell rekord mot Brasil. Hvilken?", "options": ["Norge har aldri sluppet inn mål mot Brasil", "Norge har vunnet alle kampene mot Brasil", "Norge har aldri tapt mot Brasil", "Norge har møtt Brasil flest ganger av alle"], "correct": 2, "explanation": "Norge er det eneste landet som har møtt Brasil flere ganger uten å tape — fire kamper, to seire og to uavgjort siden 1988."}, {"category": "Historie", "q": "Norges mest kjente seier over Brasil kom i VM 1998. Hva ble resultatet?", "options": ["1–0 til Norge", "2–2", "3–2 til Norge", "2–1 til Norge"], "correct": 3, "explanation": "Norge vant 2–1 i Marseille og slo dermed ut Marokko og gikk videre fra gruppa."}, {"category": "Historie", "q": "Hvem scoret Norges to mål i 2–1-seieren over Brasil i VM 1998?", "options": ["Håvard Flo og Dan Eggen", "Ole Gunnar Solskjær og Tore André Flo", "Tore André Flo og Kjetil Rekdal (straffe)", "Kjetil Rekdal og Henning Berg"], "correct": 2, "explanation": "Flo utlignet, og Rekdal satte det avgjørende straffesparket sent i kampen."}, {"category": "Historie", "q": "I hvilken by ble VM-kampen mot Brasil i 1998 spilt?", "options": ["Paris", "Marseille", "Bordeaux", "Lyon"], "correct": 1, "explanation": "Kampen ble spilt på Stade Vélodrome i Marseille 23. juni 1998."}, {"category": "Drama", "q": "Hvordan avgjorde Norge kampen mot Brasil i 1998?", "options": ["Kjetil Rekdal satte et straffespark helt på tampen (89. min)", "En scoring rett etter avspark", "Et langskudd i første omgang", "Et selvmål på overtid"], "correct": 0, "explanation": "Rekdal var iskald fra krittmerket i det 89. minutt og sikret 2–1."}, {"category": "Historie", "q": "Brasil kom først i ledelsen i 1998-kampen. Hvem scoret for Brasil?", "options": ["Ronaldo", "Bebeto", "Rivaldo", "Romário"], "correct": 1, "explanation": "Bebeto ga Brasil ledelsen før Flo og Rekdal snudde kampen for Norge."}, {"category": "Rekord", "q": "I en vennskapskamp i 1997 slo Norge Brasil klart på Ullevaal. Hva ble resultatet?", "options": ["4–2 til Norge", "3–0 til Norge", "2–1 til Norge", "1–0 til Norge"], "correct": 0, "explanation": "Norge vant 4–2 på Ullevaal — en av de mest overbevisende seirene mot Brasil noensinne."}, {"category": "Stjerner", "q": "Hvem scoret to mål for Norge i 4–2-seieren over Brasil i 1997?", "options": ["Kjetil Rekdal", "Ole Gunnar Solskjær", "Tore André Flo", "Jostein Flo"], "correct": 2, "explanation": "Tore André Flo fikk sitt store gjennombrudd på landslaget med to mål mot Brasil."}, {"category": "Historie", "q": "Da Norge og Brasil møttes aller første gang i 1988, hvordan endte det?", "options": ["0–0", "3–1 til Brasil", "1–1", "2–0 til Norge"], "correct": 2, "explanation": "Det første møtet i Oslo i 1988 endte 1–1 og la grunnlaget for en kamp Brasil aldri fikk kontroll på."}, {"category": "Kuriosa", "q": "Hva gjorde Norges 2–1-seier i 1998 ekstra oppsiktsvekkende, gitt Brasils status?", "options": ["Det var Brasils første VM-kamp noensinne", "Brasil hadde aldri tapt en VM-kamp før", "Brasil stilte uten proffspillere", "Brasil var regjerende verdensmester (vant VM i 1994)"], "correct": 3, "explanation": "Brasil hadde vunnet VM i 1994 og var tittelforsvarer — likevel felte Norge dem."}]'::jsonb, 'open', 17, true
)
