insert into public.event_quizzes (event_id, slug, num, phase, title, sub, hero_img, difficulty, questions, status, sort, published)
values (
  'vm-2026', 'pregame-norge-brasil', '18', 'Pre-game',
  'Før kampen: Norge–Brasil', 'Åttedelsfinale på MetLife — Haaland mot femdobbelt verdensmester. Ta den før avspark.', 'vm-gruppespill-1', 'middels',
  '[{"category": "Sluttspill", "q": "Når og hvor møtes Norge og Brasil i åttedelsfinalen?", "options": ["4. juli i Dallas", "5. juli på Estadio Azteca", "5. juli på MetLife Stadium i New York/New Jersey", "6. juli i Los Angeles"], "correct": 2, "explanation": "Kampen spilles 5. juli på MetLife Stadium — samme arena som VM-finalen 19. juli."}, {"category": "Norge", "q": "Hvordan tok Norge seg til åttedelsfinalen?", "options": ["På straffer mot Elfenbenskysten", "Ved å vinne gruppe I", "Som en av de beste treerne", "Ved å slå Elfenbenskysten 2–1 i 16-delsfinalen"], "correct": 3, "explanation": "Norge ble nummer to i gruppe I og slo så Elfenbenskysten 2–1 i sin første VM-utslagskamp siden 1998."}, {"category": "Norge", "q": "Norge vant 2–1 over Elfenbenskysten. Hvem scoret vinnermålet sent i kampen?", "options": ["Martin Ødegaard", "Alexander Sørloth", "Erling Haaland", "Oscar Bobb"], "correct": 2, "explanation": "Haaland stakk inn 2–1-målet i det 86. minutt; Antonio Nusa hadde sendt Norge i ledelsen."}, {"category": "Brasil", "q": "Hvordan endte Brasils gruppespill i gruppe C?", "options": ["Brasil røk ut", "Brasil gikk videre som en av treerne", "Brasil kom nummer to bak Marokko", "Brasil vant gruppa"], "correct": 3, "explanation": "Brasil vant gruppe C på målforskjell foran Marokko (1–1 mot Marokko, 3–0 mot Haiti, 3–0 mot Skottland)."}, {"category": "Brasil", "q": "Hvordan tok Brasil seg videre fra 16-delsfinalen?", "options": ["Ved å slå Marokko 2–1", "3–0 over Japan", "Ved å slå Japan 2–1", "På straffer mot Japan"], "correct": 2, "explanation": "Brasil slo Japan 2–1 i Houston; Casemiro utlignet og innbytter Martinelli avgjorde på overtid."}, {"category": "Stjerner", "q": "Hvem er Brasils store angrepsstjerne i VM 2026?", "options": ["Vinícius Júnior", "Neymar", "Ronaldo", "Kaká"], "correct": 0, "explanation": "Vinícius Júnior leder det brasilianske angrepet i VM 2026."}, {"category": "Rekord", "q": "Hvor mange ganger har Brasil vunnet VM — flest av alle nasjoner?", "options": ["Fire", "Seks", "Tre", "Fem"], "correct": 3, "explanation": "Brasil har fem VM-titler (1958, 1962, 1970, 1994 og 2002) — rekord."}, {"category": "Haaland", "q": "Hvor mange mål scoret Erling Haaland i gruppespillet i VM 2026?", "options": ["Seks", "To", "Fire", "Fem"], "correct": 2, "explanation": "To mot Irak og to mot Senegal — fire mål i gruppespillet, før han også avgjorde mot Elfenbenskysten."}, {"category": "Norge", "q": "Hvem er Norges kaptein i VM 2026?", "options": ["Martin Ødegaard", "Sander Berge", "Erling Haaland", "Alexander Sørloth"], "correct": 0, "explanation": "Arsenal-stjernen Martin Ødegaard er kaptein og Norges dirigent på midtbanen."}, {"category": "Arena", "q": "MetLife Stadium, der Norge–Brasil spilles, har en spesiell rolle i VM 2026. Hvilken?", "options": ["Det holder tilskuerrekorden i VM-historien", "Det er åpningskampens arena", "Det er det eneste stadion i Canada", "Det er også arena for VM-finalen 19. juli"], "correct": 3, "explanation": "MetLife Stadium i New Jersey er også vertsarena for VM-finalen 19. juli 2026."}]'::jsonb, 'open', 18, true
)
on conflict (event_id, slug) do update set
